function isMobile(){return window.matchMedia("(max-width: 767px)").matches}function mostrarTextoSobreMiScroll(){var e=document.querySelector(".sobre-mi-texto-contenido");if(e)if(isMobile()){var o=document.getElementById("sobre-mi");if(o){var t=o.getBoundingClientRect(),i=window.innerHeight;t.top<.7*i&&t.bottom>.3*i&&e.classList.add("visible")}}else e.classList.add("visible")}function manejarCambioTamaño(){var e=document.querySelector(".sobre-mi-texto-contenido");e&&(e.classList.remove("visible"),setTimeout(mostrarTextoSobreMiScroll,100))}document.addEventListener("DOMContentLoaded",mostrarTextoSobreMiScroll),window.addEventListener("scroll",mostrarTextoSobreMiScroll,{passive:!0}),window.addEventListener("resize",manejarCambioTamaño),window.addEventListener("orientationchange",function(){setTimeout(manejarCambioTamaño,300)});